import{_ as n,o as t,c as i,a3 as o}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"69C. Incident Reporting Investigation And Prevention","description":"","frontmatter":{"title":"69C. Incident Reporting Investigation And Prevention","eba":"Mental Health Services 2024-2028","topics":["ohs"]},"headers":[],"relativePath":"ebas/mental-health/common-terms/ohs/69C-incident-reporting-investigation-and-prevention.md","filePath":"ebas/mental-health/common-terms/ohs/69C-incident-reporting-investigation-and-prevention.md"}'),r={name:"ebas/mental-health/common-terms/ohs/69C-incident-reporting-investigation-and-prevention.md"};function a(s,e,p,l,d,c){return t(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="_69c-incident-reporting-investigation-and-prevention" tabindex="-1">69C. Incident Reporting Investigation And Prevention <a class="header-anchor" href="#_69c-incident-reporting-investigation-and-prevention" aria-label="Permalink to &quot;69C. Incident Reporting Investigation And Prevention&quot;">​</a></h1><p><strong>(a)</strong> The Employer will facilitate timely reporting of incidents by Employees and ensure Employees who report incidents are appropriately supported.</p><p><strong>(b)</strong> Following an incident, the Employee(s) will inform the Employer as soon as reasonably practicable of any occupational violence that they have experienced or witnessed.</p><p><strong>(c)</strong> Following an incident, the Employer will as soon as practicable:</p><p><strong>(i)</strong> provide all Employees with access to post incident support services, including post incident defusing support, followed by the offer of psychological counselling and individual support which may include debriefing by properly trained professionals</p><p><strong>(ii)</strong> take appropriate action to prevent further injury to Employees</p><p><strong>(iii)</strong> conduct an incident investigation in a timely manner noting the employee has a right to have a representative (including a Union representative) at any investigation meeting</p><p><strong>(iv)</strong> provide information regarding the Employee’s rights as relevant including the making and lodging of a workers compensation claim and reporting to police; and</p><p><strong>(v)</strong> allow Employees who require time off work to provide reports and statements relating to occupational violence to police and/or by Agreement other relevant authorities without loss of pay.</p><p><strong>(d)</strong> Participation in psychological support will be on a voluntary and confidential basis. It will be kept separate to any investigation of the incident and will not be used for discipline or performance management measures.</p><p><strong>(e)</strong> The Employer will provide information, instruction and training to Employees and management staff regarding the importance of timely reporting, procedures regarding incident reporting, and linking this to incident investigation and prevention.</p>',11)])])}const h=n(r,[["render",a]]);export{m as __pageData,h as default};
